**Tool 1: web_search**
```js
// Using Serper.dev API (cheap, fast, no login required for dev)
async function webSearch(query) {
  const res = await fetch('https://google.serper.dev/search', {
    method: 'POST',
    headers: { 'X-API-KEY': process.env.SERPER_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({ q: query, num: 5 })
  });
  const data = await res.json();
  return data.organic.map(r => ({ title: r.title, url: r.link, snippet: r.snippet }));
}
```

**Tool 2: read_url**
```js
import * as cheerio from 'cheerio'; // npm install cheerio
async function readUrl(url) {
  const res = await fetch(url, { signal: AbortSignal.timeout(5000) });
  const html = await res.text();
  const $ = cheerio.load(html);
  $('script, style, nav, footer, aside').remove(); // Remove noise
  const text = $('body').text().replace(/\s+/g, ' ').trim();
  return text.slice(0, 8000); // Truncate to 8K chars (~2K tokens)
}
```

**Tool 3: write_report** (save to file)
```js
async function writeReport(title, sections) {
  const md = `# ${title}\n\n${sections.map(s => `## ${s.heading}\n${s.content}`).join('\n\n')}`;
  fs.writeFileSync(`report-${Date.now()}.md`, md);
  return { success: true, filename: `report-${Date.now()}.md` };
}
```

```js
import { execFile } from 'child_process';
import { promisify } from 'util';
const execFileAsync = promisify(execFile);

async function runCode(filename) {
  try {
    const { stdout, stderr } = await execFileAsync(
      'node',
      [filename],
      {
        timeout: 10000, // 10 second timeout
        maxBuffer: 100 * 1024, // 100KB max output
        cwd: '/tmp/agent-sandbox', // Isolated directory
        env: { PATH: process.env.PATH } // Minimal environment
      }
    );
    return { exitCode: 0, stdout, stderr };
  } catch (e) {
    return {
      exitCode: e.code || 1,
      stdout: e.stdout || '',
      stderr: e.stderr || e.message
    };
  }
}
```

**Safety notes:**
- `cwd: '/tmp/agent-sandbox'` — files land in isolated temp dir, not your project
- `timeout: 10000` — agent can't run infinite loops
- `maxBuffer` — prevents memory exhaustion from large outputs
- `env: { PATH }` — agent can't access your environment variables (API keys, etc.)

```js
class WorkflowOrchestrator {
  constructor(steps) {
    this.steps = steps;
  }

  async run(input) {
    let state = { input, results: {}, errors: [] };

    for (const step of this.steps) {
      // Skip if condition not met
      if (step.condition && !step.condition(state)) continue;

      try {
        const result = await step.execute(state);
        state.results[step.name] = result;

        // Human checkpoint if required
        if (step.requiresApproval) {
          const approved = await requestApproval(step.name, result);
          if (!approved) { state.errors.push(`Step '${step.name}' rejected by human`); break; }
        }
      } catch (e) {
        state.errors.push({ step: step.name, error: e.message });
        if (step.critical) break; // Critical steps abort workflow
      }
    }

    return state;
  }
}
```

Each step is an object: `{ name, execute: async (state) => result, condition: (state) => bool, critical: bool, requiresApproval: bool }`.

Production workflows fail in the middle. Good orchestrators handle partial failures:

**1. Checkpoint + resume**
Save state after each step. If the workflow fails at step 7/10, resume from step 7.
```js
await saveCheckpoint(workflowId, stepName, state);
// On restart:
const checkpoint = await loadCheckpoint(workflowId);
const resumeFrom = steps.findIndex(s => s.name === checkpoint.lastStep) + 1;
```

**2. Idempotent steps**
Design steps that can safely run twice. If step 5 sends an email and crashes, running step 5 again shouldn't send a duplicate email.
Fix: check if email was already sent before sending.

**3. Dead letter queue**
Items that fail repeatedly should land in a 'needs human review' queue, not silently disappear.
```js
if (item.attempts >= 3) await dlq.push({ item, lastError });
else await retryQueue.push({ item, attempts: item.attempts + 1 });
```
